(function(){const e=document.getElementById("theme-select");if(!e)return;try{const t=localStorage.getItem("theme")||"";e.value=t}catch{}e.addEventListener("change",function(){const e=this.value;if(e){document.documentElement.setAttribute("data-theme",e);try{localStorage.setItem("theme",e)}catch{}}else{document.documentElement.removeAttribute("data-theme");try{localStorage.removeItem("theme")}catch{}}})})()